import { useState, useEffect } from 'react';
import axios from 'axios';

const API_BASE = 'http://localhost:8081/api/v1';

function NotificationsPanel({ visible, onHide }) {
  const [notifications, setNotifications] = useState([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [loading, setLoading] = useState(false);

  // Загружаем уведомления при открытии панели
  useEffect(() => {
    if (visible) {
      loadNotifications();
    }
  }, [visible]);

  const loadNotifications = async () => {
    try {
      setLoading(true);
      const response = await axios.get(`${API_BASE}/notifications`, {
        withCredentials: true
      });
      setNotifications(response.data.items || []);
      setUnreadCount(response.data.unreadCount || 0);
    } catch (error) {
      console.error('Failed to load notifications:', error);
    } finally {
      setLoading(false);
    }
  };

  if (!visible) return null;

  const hasNotifications = notifications.length > 0;

  return (
    <>
      {/* Overlay для закрытия при клике вне панели */}
      <div 
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          zIndex: 999
        }}
        onClick={onHide}
      />
      
      {/* Панель уведомлений */}
      <div
        style={{
          position: 'fixed',
          top: '80px',
          right: '210px',
          width: '406px',
          minHeight: '336px',
          maxHeight: '600px',
          background: '#FFFFFF',
          borderRadius: '14px',
          boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
          zIndex: 1000,
          display: 'flex',
          flexDirection: 'column',
          overflow: 'hidden'
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Заголовок */}
        <div style={{
          padding: '1.5rem',
          borderBottom: hasNotifications ? '1px solid #e5e7eb' : 'none',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          flexShrink: 0
        }}>
          <h3 style={{
            fontSize: '20px',
            fontWeight: '600',
            color: '#1e293b',
            margin: 0
          }}>
            Уведомления
          </h3>
          <button
            onClick={onHide}
            style={{
              background: 'transparent',
              border: 'none',
              cursor: 'pointer',
              padding: '4px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: '#64748b'
            }}
          >
            <i className="pi pi-times" style={{ fontSize: '18px' }}></i>
          </button>
        </div>

        {/* Контент */}
        {hasNotifications ? (
          <div style={{
            flex: 1,
            overflowY: 'auto',
            padding: '0.5rem 0'
          }}>
            {notifications.map((notification) => (
              <div
                key={notification.id}
                style={{
                  padding: '12px 1.5rem',
                  display: 'flex',
                  alignItems: 'flex-start',
                  gap: '12px',
                  cursor: 'pointer',
                  transition: 'background 0.2s',
                  background: notification.isRead ? 'transparent' : '#f8fafc'
                }}
                onMouseEnter={(e) => e.currentTarget.style.background = '#f1f5f9'}
                onMouseLeave={(e) => e.currentTarget.style.background = notification.isRead ? 'transparent' : '#f8fafc'}
              >
                {/* Индикатор непрочитанного */}
                <div style={{
                  width: '10px',
                  height: '10px',
                  borderRadius: '50%',
                  background: notification.isRead ? 'transparent' : '#3B82F6',
                  marginTop: '4px',
                  flexShrink: 0
                }}></div>

                {/* Текст уведомления */}
                <div style={{ flex: 1 }}>
                  <p style={{
                    fontSize: '14px',
                    fontWeight: '400',
                    color: '#475569',
                    margin: 0,
                    lineHeight: '1.5'
                  }}>
                    {notification.message}
                  </p>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div style={{
            padding: '0 1.5rem 1.5rem 1.5rem',
            paddingTop: '0.5rem',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'flex-start',
            justifyContent: 'flex-start',
            flex: 1,
            position: 'relative',
            overflow: 'hidden'
          }}>
            <div style={{ 
              display: 'flex', 
              flexDirection: 'column',
              gap: '4px',
              width: '100%',
              position: 'relative',
              zIndex: 2
            }}>
              <p style={{ 
                fontSize: '15px', 
                fontWeight: '600', 
                color: '#000000',
                margin: 0,
                lineHeight: '0.3'
              }}>
                Список уведомлений пуст...
              </p>
              <p style={{ 
                fontSize: '15px', 
                fontWeight: '400', 
                color: '#000000',
                margin: 0,
                lineHeight: '1.3'
              }}>
                загляните позже, вдруг что-нибудь появится
              </p>
            </div>

            {/* Герой */}
            <img 
              src="/images/monstr.svg" 
              alt="Персонаж" 
              style={{
                position: 'absolute',
                bottom: '-10px',
                right: '-10px',
                width: '240px',
                height: 'auto',
                zIndex: 1
              }}
            />
          </div>
        )}
      </div>
    </>
  );
}

export default NotificationsPanel;
